local G = DYCLegendary local require = G.DYCModRequire local enchantmentSystem = require( "dyc_enchantments" ) local enchantmentList = enchantmentSystem.list local bonusList = enchantmentSystem.bonusList local function ClearFollowingFXs(self) if self.dycFollowingFXs then for k, v in pairs(self.dycFollowingFXs) do if v:IsValid() then v:Remove() end end end self.dycFollowingFXs = {} end local function Unequip(self, owner, slot, ...) local health = owner and owner.components.health local oldhp = health and health:GetPercent() if owner and owner.RecalcCharacterEnchantmentBonus then owner:DoTaskInTime(0x0, function() owner:RecalcCharacterEnchantmentBonus(bonusList) if oldhp then health:SetPercent(oldhp) end end) end if self.inst.InvokeEventUnequip then self.inst:InvokeEventUnequip(owner, slot) end ClearFollowingFXs(self) return self.dycOldUnequip(self, owner, slot, ...) end local function Equip(self, owner, slot, ...) local health = owner and owner.components.health local oldhp = health and health:GetPercent() if owner and owner.RecalcCharacterEnchantmentBonus then owner:DoTaskInTime(0x0, function() owner:RecalcCharacterEnchantmentBonus(bonusList) if oldhp then health:SetPercent(oldhp) end end) end if self.inst.InvokeEventEquip then self.inst:InvokeEventEquip(owner, slot) end ClearFollowingFXs(self) if self.dycFollowingFXdata then for k, v in pairs(self.dycFollowingFXdata) do local fx = SpawnPrefab(v.prefab) if v.scale and fx.SetPercentage then fx:SetPercentage(v.scale) end if v.delay and fx.SetDelay then fx:SetDelay(v.delay) end if v.lifespan and fx.isDYCParticle then fx:Remove(v.lifespan) end local follower = fx.entity:AddFollower() follower:FollowSymbol(owner.GUID, v.follow, v.x or 0x0, v.y or 0x0, v.z or 0x0) table.insert(self.dycFollowingFXs, fx) end end return self.dycOldEquip(self, owner, slot, ...) end local function SetFollowingFXs(self, fxs) ClearFollowingFXs(self) self.dycFollowingFXdata = fxs end local function DYCEquippable(self) self.dycOldEquip = self.Equip self.Equip = Equip self.dycOldUnequip = self.Unequip self.Unequip = Unequip self.SetFollowingFXs = SetFollowingFXs end return DYCEquippable 